	private static final String EX = "http://example.com/aggregation/";
	private static final int FEW_GROUP_COUNT = 8;
	private static final int WIDE_KEY_COUNT = 6;
	private static final int WIDE_GROUP_REPEAT = 4;
	private static final long DIGEST_OFFSET = 0xcbf29ce484222325L;
	private static final long DIGEST_PRIME = 0x100000001b3L;
	private static final String SPILL_KEY_SUFFIX = "-0123456789abcdef0123456789abcdef0123456789abcdef0123456789abcdef";

	@Param({ "65536" })
	public int inputRows;

